package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.IOException;
import java.io.Reader;
import java.io.Serializable;
import java.io.StringWriter;
import java.sql.ResultSet;
import java.sql.ResultSetMetaData;
import java.sql.SQLException;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testIsCommentMarkerSet_whenCommentMarkerIsNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        // commentMarker is private final, but withCommentMarker(null) creates new instance with null commentMarker
        CSVFormat newFormat = format.withCommentMarker((Character) null);
        assertFalse(newFormat.isCommentMarkerSet());
    }

    @Test
    void testIsCommentMarkerSet_whenCommentMarkerIsSet() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withCommentMarker('#');
        assertTrue(format.isCommentMarkerSet());
    }

    @Test
    void testIsCommentMarkerSet_reflectivelySetCommentMarkerNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withCommentMarker('#');
        Field commentMarkerField = CSVFormat.class.getDeclaredField("commentMarker");
        commentMarkerField.setAccessible(true);

        // forcibly set commentMarker to null on the new instance (create a new instance with reflection)
        // Since commentMarker is final, setting it on existing instance may not work reliably.
        // Instead, create a new instance via reflection copying all fields except commentMarker=null

        CSVFormat newFormat = createCSVFormatWithCommentMarker(format, null);

        assertFalse(newFormat.isCommentMarkerSet());
    }

    @Test
    void testIsCommentMarkerSet_reflectivelySetCommentMarkerChar() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat newFormat = createCSVFormatWithCommentMarker(format, '#');
        assertTrue(newFormat.isCommentMarkerSet());
    }

    // Helper method to create a new CSVFormat instance with the same fields as original but with specified commentMarker
    private CSVFormat createCSVFormatWithCommentMarker(CSVFormat original, Character commentMarker) throws Exception {
        Field delimiterField = CSVFormat.class.getDeclaredField("delimiter");
        Field quoteCharacterField = CSVFormat.class.getDeclaredField("quoteCharacter");
        Field quoteModeField = CSVFormat.class.getDeclaredField("quoteMode");
        Field escapeCharacterField = CSVFormat.class.getDeclaredField("escapeCharacter");
        Field ignoreSurroundingSpacesField = CSVFormat.class.getDeclaredField("ignoreSurroundingSpaces");
        Field allowMissingColumnNamesField = CSVFormat.class.getDeclaredField("allowMissingColumnNames");
        Field ignoreEmptyLinesField = CSVFormat.class.getDeclaredField("ignoreEmptyLines");
        Field recordSeparatorField = CSVFormat.class.getDeclaredField("recordSeparator");
        Field nullStringField = CSVFormat.class.getDeclaredField("nullString");
        Field headerField = CSVFormat.class.getDeclaredField("header");
        Field headerCommentsField = CSVFormat.class.getDeclaredField("headerComments");
        Field skipHeaderRecordField = CSVFormat.class.getDeclaredField("skipHeaderRecord");
        Field ignoreHeaderCaseField = CSVFormat.class.getDeclaredField("ignoreHeaderCase");

        delimiterField.setAccessible(true);
        quoteCharacterField.setAccessible(true);
        quoteModeField.setAccessible(true);
        escapeCharacterField.setAccessible(true);
        ignoreSurroundingSpacesField.setAccessible(true);
        allowMissingColumnNamesField.setAccessible(true);
        ignoreEmptyLinesField.setAccessible(true);
        recordSeparatorField.setAccessible(true);
        nullStringField.setAccessible(true);
        headerField.setAccessible(true);
        headerCommentsField.setAccessible(true);
        skipHeaderRecordField.setAccessible(true);
        ignoreHeaderCaseField.setAccessible(true);

        char delimiter = (char) delimiterField.get(original);
        Character quoteChar = (Character) quoteCharacterField.get(original);
        Object quoteMode = quoteModeField.get(original);
        Character escapeChar = (Character) escapeCharacterField.get(original);
        boolean ignoreSurroundingSpaces = (boolean) ignoreSurroundingSpacesField.get(original);
        boolean allowMissingColumnNames = (boolean) allowMissingColumnNamesField.get(original);
        boolean ignoreEmptyLines = (boolean) ignoreEmptyLinesField.get(original);
        String recordSeparator = (String) recordSeparatorField.get(original);
        String nullString = (String) nullStringField.get(original);
        Object[] headerComments = (Object[]) headerCommentsField.get(original);
        String[] header = (String[]) headerField.get(original);
        boolean skipHeaderRecord = (boolean) skipHeaderRecordField.get(original);
        boolean ignoreHeaderCase = (boolean) ignoreHeaderCaseField.get(original);

        // CSVFormat constructor:
        // private CSVFormat(final char delimiter, final Character quoteChar, final QuoteMode quoteMode,
        // final Character commentStart, final Character escape, final boolean ignoreSurroundingSpaces,
        // final boolean ignoreEmptyLines, final String recordSeparator, final String nullString,
        // final Object[] headerComments, final String[] header, final boolean skipHeaderRecord,
        // final boolean allowMissingColumnNames, final boolean ignoreHeaderCase)

        // In case quoteMode is an enum or class, cast accordingly
        return new CSVFormat(
                delimiter,
                quoteChar,
                (QuoteMode) quoteMode,
                commentMarker,
                escapeChar,
                ignoreSurroundingSpaces,
                ignoreEmptyLines,
                recordSeparator,
                nullString,
                headerComments,
                header,
                skipHeaderRecord,
                allowMissingColumnNames,
                ignoreHeaderCase
        );
    }
}
